// ML pipeline architectural reference for Staff+ engineers
// This is the data flow for a typical production ML system at FAANG

interface MLPipeline {
  dataIngestion: {
    sources: ["Kafka topics", "Database CDC", "S3 event logs"],
    processing: "Apache Beam / Flink streaming pipelines",
    validation: "Great Expectations / custom data quality checks",
    storage: "Data lake (Parquet) + Feature store"
  };

  featureEngineering: {
    batchFeatures: "Spark jobs, daily computation",
    realtimeFeatures: "Flink jobs, sub-second latency",
    featureStore: "Online (Redis/Aerospike) + Offline (BigQuery/S3)",
    consistency: "Point-in-time correct join between features and labels"
  };

  training: {
    framework: "PyTorch / TensorFlow / JAX",
    orchestrator: "Kubeflow / Airflow / Meta Flow",
    hyperparameterTuning: "Vizier / Optuna",
    experimentTracking: "MLflow / Weights & Biases / internal tool"
  };

  serving: {
    inferencePlatform: "NVIDIA Triton / TensorFlow Serving / TorchServe",
    latency: "<50ms p99 for online, <500ms for nearline",
    batching: "Dynamic batching with max latency SLO",
    caching: "Feature cache + prediction cache with TTL"
  };

  monitoring: {
    modelMetrics: "Accuracy, precision, recall, AUC per segment",
    dataDrift: "KS-test, PSI, distribution distance per feature",
    predictionDrift: "Output distribution shift detection",
    infrastructure: "p50/p99 latency, throughput, error rates"
  };
}

// RAG architecture reference for Staff+ engineers
// This pattern is used across FAANG for LLM-powered features

interface RAGSystem {
  ingestion: {
    chunking: "RecursiveCharacterTextSplitter (500-1000 tokens per chunk)",
    embeddings: "text-embedding-3-large / multilingual-e5-large",
    vectorDB: "Pinecone / Weaviate / FAISS / internal solution",
    metadata: "source, date, permissions, version tracking"
  };

  retrieval: {
    query: "User query → embedding → vector similarity search",
    topK: 5,
    filters: "Metadata filtering (date range, source type, permissions)",
    reranking: "Cross-encoder reranker for precision",
    latency: "<100ms p99 from query to retrieved documents"
  };

  generation: {
    promptTemplate: "System prompt + {retrieved_context} + User query",
    model: "GPT-4 / Claude 3 / Gemini for complex, smaller model for simple",
    temperature: 0.1, // Low for factual accuracy
    maxTokens: 1024,
    guardrails: "Output filtering for PII, toxicity, hallucination detection"
  };

  evaluation: {
    metrics: ["answer_relevancy", "faithfulness", "context_precision"],
    automatedEval: "LLM-as-judge (GPT-4 rates outputs)",
    humanEval: "Monthly sample review by domain experts",
    regression: "Weekly eval on fixed test set of 500 queries"
  };
}
